    pub fn parse_transaction_status(&self, mut status: Value) -> Value {
        // Pending the record is wait broadcast to chain
        // x/M confirming the comfirming state of tx, the M is total confirmings needed
        // SUCCESS the record is success full
        // FAIL the record failed
        let mut parts: Value = split(&status, &Value::Str(" ".to_string()));
        status = self.safe_string(parts.clone(), Value::Int(1), &[status.clone()]);
        let mut statuses: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("Pending".to_string(), Value::Str("pending".to_string()));
                m.insert("confirming".to_string(), Value::Str("pending".to_string()));
                m.insert("SUCCESS".to_string(), Value::Str("ok".to_string()));
                m.insert("FAIL".to_string(), Value::Str("failed".to_string()));
            m
        });
        return self.safe_string(statuses.clone(), status.clone(), &[status.clone()]);

    Value::Null
}

    pub fn parse_transaction(&self, mut transaction: Value, optional_args: &[Value]) -> Value {
        let mut currency = get_arg(optional_args, 0, Value::Null);
        //
        // withdraw
        //
        //     {
        //         "code":"A10000",
        //         "data": "DR123",
        //         "message":"Success"
        //     }
        //
        // fetchDepositsWithdrawals
        //
        //     {
        //         "id": "DR562339304588709888",
        //         "type": "COIN_IN",
        //         "currency": "XLM",
        //         "chain": "XLM",
        //         "address": "GCUTK7KHPJC3ZQJ3OMWWFHAK2OXIBRD4LNZQRCCOVE7A2XOPP2K5PU5Q",
        //         "addressTag": "1000009",
        //         "amount": 1.0,
        //         "state": "SUCCESS",
        //         "txHash": "39210645748822f8d4ce673c7559aa6622e6e9cdd7073bc0fcae14b1edfda5f4",
        //         "createdAt": 1554113737000,
        //         "updatedAt": 1601371273000
        //     }
        //
        let mut id: Value = self.safe_string2(transaction.clone(), Value::Str("id".to_string()), Value::Str("data".to_string()), &[]);
        let mut type_var: Value = self.safe_string_k(transaction.clone(), "type", &[]);
        if is_equal(&type_var, &Value::Str("COIN_IN".to_string())) {
            type_var = Value::Str("deposit".to_string());
        }  else if is_equal(&type_var, &Value::Str("COIN_OUT".to_string())) {
            type_var = Value::Str("withdraw".to_string());
        }
        let mut amount: Value = self.safe_number_k(transaction.clone(), "amount", &[]);
        let mut address: Value = self.safe_string_k(transaction.clone(), "address", &[]);
        let mut tag: Value = self.safe_string_k(transaction.clone(), "addressTag", &[]);
        let mut txid: Value = self.safe_string_k(transaction.clone(), "txHash", &[]);
        let mut timestamp: Value = self.safe_integer_k(transaction.clone(), "createdAt", &[]);
        let mut updated: Value = self.safe_integer_k(transaction.clone(), "updatedAt", &[]);
        let mut currencyId: Value = self.safe_string_k(transaction.clone(), "currency", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[currency.clone()]);
        let mut status: Value = self.parse_transaction_status(self.safe_string_k(transaction.clone(), "state", &[]));
        let mut network: Value = self.safe_string_k(transaction.clone(), "chain", &[]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), transaction.clone());
        m.insert("id".to_string(), id.clone());
        m.insert("currency".to_string(), code.clone());
        m.insert("amount".to_string(), amount.clone());
        m.insert("network".to_string(), network.clone());
        m.insert("address".to_string(), address.clone());
        m.insert("addressTo".to_string(), address.clone());
        m.insert("addressFrom".to_string(), Value::Null);
        m.insert("tag".to_string(), tag.clone());
        m.insert("tagTo".to_string(), tag.clone());
        m.insert("tagFrom".to_string(), Value::Null);
        m.insert("status".to_string(), status.clone());
        m.insert("type".to_string(), type_var.clone());
        m.insert("updated".to_string(), updated.clone());
        m.insert("txid".to_string(), txid.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("comment".to_string(), Value::Null);
        m.insert("internal".to_string(), Value::Null);
        m.insert("fee".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("currency".to_string(), Value::Null);
        m.insert("cost".to_string(), Value::Null);
        m.insert("rate".to_string(), Value::Null);
    m
}));
    m
});

    Value::Null
}

